function doGet(e) {
  // 1. HARDCODE THE ID OF YOUR SINGLE HTML TEMPLATE HERE
  var templateId = '1u7NjTMeOSnK5phJAgG6RLT6OEsUqzqX3'; 

  // 2. GET THE PDF ID AND TITLE FROM MOODLE
  var pdfId = e.parameter.pdfId;
  var title = e.parameter.title || 'Documento PDF'; // Fallback if no title is sent

  if (!pdfId) {
    return ContentService.createTextOutput("Error: Falta el parámetro pdfId en la URL.")
           .setMimeType(ContentService.MimeType.TEXT);
  }

  try {
    // 3. READ THE TEMPLATE
    var file = DriveApp.getFileById(templateId);
    var content = file.getBlob().getDataAsString();

    // 4. INJECT THE DYNAMIC DATA
    // We use a regex with 'g' to replace all instances just in case
    content = content.replace(/{{PDF_ID}}/g, pdfId);
    content = content.replace(/{{PDF_TITLE}}/g, title);

    // 5. RETURN THE MODIFIED HTML AS TEXT
    return ContentService.createTextOutput(content)
           .setMimeType(ContentService.MimeType.TEXT);

  } catch (err) {
    return ContentService.createTextOutput("Error: No se encontró la plantilla o no tienes permisos.")
           .setMimeType(ContentService.MimeType.TEXT);
  }
}
